def decode_hieroglyphic_sum(hieroglyphs: str) -> int:
    values = {'I': 1, 'V': 5, 'X': 10}
    total = 0
    for i in range(len(hieroglyphs)):
        if i > 0 and values.get(hieroglyphs[i], 0) < values.get(hieroglyphs[i - 1], 0):
            total += values.get(hieroglyphs[i], 0)
        else:
            total += values.get(hieroglyphs[i], 0) * (i + 1)
    return total
